// ── Helper functions ───────────────────────────────────────────

func stateLabel(state string) string {
	switch state {
	case StateBacklog:
		return "Backlog"
	case StateTodo:
		return "Todo"
	case StateDoing:
		return "In Progress"
	case StateReview:
		return "Review"
	case StateDone:
		return "Done"
	default:
		return state
	}
}

func stateBgClass(state string) string {
	switch state {
	case StateBacklog:
		return "bg-slate-100 text-slate-600"
	case StateTodo:
		return "bg-gray-100 text-gray-600"
	case StateDoing:
		return "bg-indigo-100 text-indigo-700"
	case StateReview:
		return "bg-amber-100 text-amber-700"
	case StateDone:
		return "bg-emerald-100 text-emerald-700"
	default:
		return "bg-gray-100 text-gray-600"
	}
}

func stateColorHex(state string) string {
	switch state {
	case StateBacklog:
		return "#94A3B8"
	case StateTodo:
		return "#6B7280"
	case StateDoing:
		return "#6366F1"
	case StateReview:
		return "#F59E0B"
	case StateDone:
		return "#10B981"
	default:
		return "#6B7280"
	}
}

// stateColor returns Tailwind classes for state badges (kept for
// compatibility but new code should prefer stateBgClass).
func stateColor(state string) string {
	return stateBgClass(state)
}

// priorityColor returns Tailwind classes for priority badges.
func priorityColor(priority string) string {
	switch priority {
	case PriorityUrgent:
		return "bg-red-100 text-red-700"
	case PriorityHigh:
		return "bg-amber-100 text-amber-700"
	case PriorityMedium:
		return "bg-gray-100 text-gray-600"
	case PriorityLow:
		return "bg-gray-50 text-gray-400"
	default:
		return "bg-gray-100 text-gray-600"
	}
}

