func assigneeInitial(name string) string {
	if name == "" {
		return ""
	}
	runes := []rune(name)
	if len(runes) == 0 {
		return ""
	}
	return string(runes[0:1])
}

func nextState(state string) string {
	switch state {
	case StateBacklog:
		return StateTodo
	case StateTodo:
		return StateDoing
	case StateDoing:
		return StateReview
	case StateReview:
		return StateDone
	default:
		return state
	}
}

func prevState(state string) string {
	switch state {
	case StateDone:
		return StateReview
	case StateReview:
		return StateDoing
	case StateDoing:
		return StateTodo
	case StateTodo:
		return StateBacklog
	default:
		return state
	}
}

func subtaskProgress(task Task) string {
	if task.SubtaskCount == 0 {
		return "width: 0%"
	}
	pct := (task.SubtaskDone * 100) / task.SubtaskCount
	return fmt.Sprintf("width: %d%%", pct)
}

func subtaskProgress2(tasks []Task) string {
	if len(tasks) == 0 {
		return "width: 0%"
	}
	done := countDone(tasks)
	pct := (done * 100) / len(tasks)
	return fmt.Sprintf("width: %d%%", pct)
}

func countDone(tasks []Task) int {
	n := 0
	for _, t := range tasks {
		if t.State == StateDone {
			n++
		}
	}
	return n
}

func labelStyle(label Label) string {
	return fmt.Sprintf("background: %s20; color: %s", label.Color, label.Color)
}

